helper_lemmas:
proof fn lemma_va_range_4k_view_unique(va: VAddr, len: usize, r1: VaRange4K, r2: VaRange4K)
    requires
        r1.wf(),
        r2.wf(),
        r1.start == va,
        r2.start == va,
        r1.len == len,
        r2.len == len,
    ensures
        r1.start == r2.start,
        r1.len == r2.len,
        r1@.len() == r2@.len(),
        r1@ == r2@,
{
    reveal(VaRange4K::view_match_spec);

    assert(r1@.len() == r1.len);
    assert(r2@.len() == r2.len);
    assert(r1@.len() == r2@.len());
    assert(r1.view_match_spec());
    assert(r2.view_match_spec());

    assert forall|i: int| 0 <= i < r1@.len() implies r1@[i] == r2@[i] by {
        assert(r1@.len() == r1.len);
        assert(r2@.len() == r2.len);
        assert(i < r1.len);
        assert(i < r2.len);
        assert(0 <= i < usize::MAX);
        let iu: usize = i as usize;
        assert(iu as int == i);
        assert(0 <= iu < r1.len);
        assert(0 <= iu < r2.len);
        assert(spec_va_add_range(r1.start, iu) == r1@[iu as int]);
        assert(spec_va_add_range(r2.start, iu) == r2@[iu as int]);
        assert(r1.start == r2.start);
        assert(spec_va_add_range(r1.start, iu) == spec_va_add_range(r2.start, iu));
        assert(r1@[iu as int] == r2@[iu as int]);
        assert(r1@[i] == r1@[iu as int]);
        assert(r2@[i] == r2@[iu as int]);
    };

    assert(r1@ =~= r2@);
}
